  function appendMissingToolDefs(existingTools, extraTools) {
    const seen = new Set(
      (existingTools || []).map((tool) => tool?.function?.name).filter(Boolean)
    );
    return [
      ...existingTools || [],
      ...extraTools.filter((tool) => {
        const name = tool?.function?.name;
        if (!name || seen.has(name))
          return false;
        seen.add(name);
        return true;
      })
    ];
  }
