  async function sendMessageDirect(options) {
    const digits = normalizePhoneDigitsForCus(options.phone);
    if (!digits) {
      const err = "Invalid phone number for WhatsApp (need 8\u201315 digits)";
      console.warn("[WhatsApp Sender]", err, options.phone);
      if (!options.skipMessageLogger)
        await logMessageFailed(options);
      return { success: false, error: err };
    }
    const storeResult = await sendTextViaWaWebStoreQueued(
      digits,
      options.message,
      options.replyToWaMessageId
    );
    if (storeResult.success) {
      if (!options.skipTracking)
        await saveMessageTracking(options);
      if (!options.skipMessageLogger)
        await logMessageSent(options);
      extLog("[WhatsApp Sender] \u2705 Sent via WA store API:", digits);
      return { success: true };
    }
    console.warn("[WhatsApp Sender] WA store API failed:", storeResult.error);
    if (!options.skipMessageLogger)
      await logMessageFailed(options);
    return {
      success: false,
      error: storeResult.error || "WhatsApp store send failed"
    };
  }
