  async function checkConversation() {
    if (!checkContext())
      return;
    const now = Date.now();
    if (now - lastHeaderCheck < CONFIG2.DEBOUNCE_MS)
      return;
    lastHeaderCheck = now;
    const resolved = await getPhoneAndPushnameFromChat();
    if (!resolved) {
      const panel = document.getElementById(CONFIG2.PANEL_ID);
      if (panel)
        panel.remove();
      currentPhone = null;
      return;
    }
    const { phone, pushname } = resolved;
    const phoneSuffix = getPhoneSuffix(phone);
    const currentSuffix = currentPhone ? getPhoneSuffix(currentPhone) : null;
    if (phoneSuffix !== currentSuffix) {
      currentPhone = phone;
      await injectHeaderPanel(phone, pushname);
    }
  }
  async function initHeaderInfoInjector() {
    extLog("[Header Info] \u{1F680} Initializing v6.0 (MutationObserver + EventBus)...");
    if (headerObserver) {
      headerObserver.disconnect();
      headerObserver = null;
    }
    setupEventBusListeners();
    const observer = new MutationObserver(debounce(async (mutations) => {
      for (const mutation of mutations) {
        if (mutation.type === "childList" || mutation.type === "characterData") {
          await checkConversation();
          break;
        }
      }
    }, CONFIG2.DEBOUNCE_MS));
    const mainContainer = document.querySelector("#app") || document.querySelector("#main") || document.body;
    if (mainContainer) {
      observer.observe(mainContainer, {
        childList: true,
        subtree: true,
        characterData: true
      });
      headerObserver = observer;
      extLog("[Header Info] \u2705 MutationObserver attached to:", mainContainer.id || mainContainer.tagName);
    } else {
      console.error("[SmartDM Header Panel] \u274C Could not find #app, #main or body to observe \u2014 header panel will not auto-update");
    }
    await checkConversation();
    extLog("[Header Info] \u2705 Initialized with MutationObserver + EventBus");
  }
  function setupEventBusListeners() {
    extLog("[Header Info] \u{1F4E1} Setting up EventBus listeners...");
    eventBus.on("contact-added", () => {
      if (currentPhone)
        refreshHeaderPanel();
    });
    eventBus.on("contact-updated", (data) => {
      if (currentPhone) {
        const currentSuffix = getPhoneSuffix(currentPhone);
        const eventSuffix = data.phone ? getPhoneSuffix(data.phone) : null;
        if (currentSuffix === eventSuffix)
          refreshHeaderPanel();
      }
    });
    eventBus.on("flow-created", () => {
    });
    eventBus.on("flow-execution-created", (data) => {
      extLog("[Header Info] \u{1F4E5} Flow execution created for contactId:", data.contactId);
      refreshHeaderIfRelevant(data.contactId);
    });
    eventBus.on("flow-execution-updated", (data) => {
      refreshHeaderIfRelevant(data.contactId);
    });
    eventBus.on("campaign-created", () => {
    });
    eventBus.on("campaign-updated", () => {
    });
    eventBus.on("badge-created", (data) => {
      extLog("[Header Info] \u{1F4E5} Badge created for phone:", data.phone);
      if (currentPhone) {
        const currentSuffix = getPhoneSuffix(currentPhone);
        const eventSuffix = data.phone ? getPhoneSuffix(data.phone) : null;
        if (currentSuffix === eventSuffix) {
          refreshHeaderPanel();
        }
      }
    });
    eventBus.on("badge-updated", (data) => {
      extLog("[Header Info] \u{1F4E5} Badge updated for phone:", data.phone);
      if (currentPhone) {
        const currentSuffix = getPhoneSuffix(currentPhone);
        const eventSuffix = data.phone ? getPhoneSuffix(data.phone) : null;
        if (currentSuffix === eventSuffix) {
          refreshHeaderPanel();
        }
      }
    });
    eventBus.on("cache-invalidate", (data) => {
      if ((data.cacheType === "crm" || data.cacheType === "all") && currentPhone) {
        refreshHeaderPanel();
      }
    });
    extLog("[Header Info] \u2705 EventBus listeners ready");
  }
  async function refreshHeaderIfRelevant(contactId) {
    if (!currentPhone)
      return;
    const contact = await findCrmContactById(contactId);
    if (contact) {
      const currentSuffix = getPhoneSuffix(currentPhone);
      const contactSuffix = contact.phoneNumber ? getPhoneSuffix(contact.phoneNumber) : null;
      if (currentSuffix === contactSuffix)
        refreshHeaderPanel();
    }
  }
  function debounce(func, wait) {
    let timeout = null;
    return (...args) => {
      if (timeout)
        clearTimeout(timeout);
      timeout = setTimeout(() => func(...args), wait);
    };
  }
  async function refreshHeaderPanel() {
    if (currentPhone) {
      const resolved = await getPhoneAndPushnameFromChat();
      const pushname = resolved?.phone && getPhoneSuffix(resolved.phone) === getPhoneSuffix(currentPhone) ? resolved.pushname : null;
      await injectHeaderPanel(currentPhone, pushname);
    }
  }

