  function getCurrentPhone() {
    const headerSpan = document.querySelector("header span[title]");
    if (headerSpan) {
      const title = headerSpan.getAttribute("title");
      if (title) {
        const digits = title.replace(/\D/g, "");
        if (digits.length >= 9) {
          return title;
        }
      }
    }
    const input = document.querySelector('[data-lexical-editor="true"]');
    const label = input?.getAttribute("aria-label");
    if (label) {
      const match = label.match(/Type to (.+)/i);
      if (match && match[1]) {
        const phone = match[1].trim();
        const digits = phone.replace(/\D/g, "");
        if (digits.length >= 9) {
          return phone;
        }
      }
    }
    const hashMatch = window.location.hash.match(/\/(\d+)@/);
    if (hashMatch) {
      return "+" + hashMatch[1];
    }
    const headerElements = document.querySelectorAll("#main header span, header[data-testid] span");
    for (const el of headerElements) {
      const text = el.textContent || "";
      const digits = text.replace(/\D/g, "");
      if (digits.length >= 9 && digits.length <= 15) {
        return text;
      }
    }
    const mainHeader = document.querySelector("#main header");
    if (mainHeader) {
      const allSpans = mainHeader.querySelectorAll('span[dir="auto"]');
      for (const span of allSpans) {
        const title = span.getAttribute("title") || span.textContent || "";
        const digits = title.replace(/\D/g, "");
        if (digits.length >= 9) {
          return title;
        }
      }
    }
    extLog("[Schedule] Could not find phone number");
    return null;
  }
  async function resolvePhoneFromCurrentChat() {
    const msgEl = document.querySelector('#main [data-id^="true_"], #main [data-id^="false_"]');
    if (!msgEl)
      return null;
    const dataId = msgEl.getAttribute("data-id") || "";
    if (!dataId)
      return null;
    try {
      const { parseMessageId: parseMessageId2, getContact: getContact2, extractPhoneFromContactId: extractPhoneFromContactId2 } = await Promise.resolve().then(() => (init_WhatsAppIndexedDBService(), WhatsAppIndexedDBService_exports));
      const { contactId } = parseMessageId2(dataId);
      if (!contactId)
        return null;
      const waContact = await getContact2(contactId);
      if (!waContact)
        return null;
      let phone = "";
      if (waContact.phoneNumber) {
        phone = extractPhoneFromContactId2(waContact.phoneNumber);
      }
      if (!phone && waContact.id) {
        const idPart = waContact.id.split("@")[0];
        if (/^\d{10,15}$/.test(idPart))
          phone = "+" + idPart;
      }
      if (!phone)
        return null;
      if (!phone.startsWith("+"))
        phone = "+" + phone;
      const contactName = waContact.pushname || waContact.name || phone;
      return { phone, contactName };
    } catch (e) {
      console.warn("[Schedule] resolvePhoneFromCurrentChat failed:", e);
      return null;
    }
  }
  function getMessageText() {
    const editor = document.querySelector('[data-lexical-editor="true"]');
    if (!editor)
      return "";
    const paragraphs = editor.querySelectorAll("p");
    let text = "";
    paragraphs.forEach((p) => {
      const content = p.textContent || "";
      if (content && content !== "Type a message") {
        text += content + "\n";
      }
    });
    return text.trim();
  }
