  function addButtonEffects() {
    const t5 = getTheme();
    const buttons = document.querySelectorAll("#smartdm-welcome-panel button");
    buttons.forEach((btn) => {
      const button = btn;
      const originalBg = button.style.background;
      button.addEventListener("mouseenter", () => {
        if (button.id === "smartdm-upgrade-btn") {
          button.style.transform = "translateY(-2px)";
          button.style.boxShadow = "0 6px 24px rgba(32, 178, 170, 0.4)";
        } else {
          button.style.background = t5.btnHoverBg;
          button.style.borderColor = "#20B2AA";
        }
      });
      button.addEventListener("mouseleave", () => {
        if (button.id === "smartdm-upgrade-btn") {
          button.style.transform = "translateY(0)";
          button.style.boxShadow = "0 4px 16px rgba(32, 178, 170, 0.3)";
        } else {
          button.style.background = originalBg || t5.btnBg;
          button.style.borderColor = t5.btnBorder;
        }
      });
    });
  }
