  function addLandingClickHandlers() {
    document.getElementById("smartdm-login-btn")?.addEventListener("click", () => {
      window.open("https://birthday.agent0s.dev/public/account/login?from=extension", "_blank");
    });
    document.getElementById("smartdm-signup-btn")?.addEventListener("click", () => {
      window.open("https://birthday.agent0s.dev/public/account/register?from=extension", "_blank");
    });
    const loginBtn = document.getElementById("smartdm-login-btn");
    const signupBtn = document.getElementById("smartdm-signup-btn");
    const t5 = getTheme();
    loginBtn?.addEventListener("mouseenter", () => {
      loginBtn.style.background = t5.btnHoverBg;
    });
    loginBtn?.addEventListener("mouseleave", () => {
      loginBtn.style.background = t5.btnBg;
    });
    signupBtn?.addEventListener("mouseenter", () => {
      signupBtn.style.transform = "translateY(-2px)";
      signupBtn.style.boxShadow = "0 6px 24px rgba(32, 178, 170, 0.4)";
    });
    signupBtn?.addEventListener("mouseleave", () => {
      signupBtn.style.transform = "translateY(0)";
      signupBtn.style.boxShadow = "0 4px 16px rgba(32, 178, 170, 0.3)";
    });
  }
  function findMainContainer() {
    const businessIcon = document.querySelector('[data-icon="wds-smb-ill-start-a-chat"]');
    if (businessIcon) {
      const container = businessIcon.closest(".xktia5q");
      if (container) {
        extLog("[SmartDM] Found business illustration container (.xktia5q)");
        return container;
      }
    }
    const allSections = document.querySelectorAll("section");
    for (const sec of allSections) {
      if (sec.classList.contains("x6egj2d") || sec.className.includes("x6egj2d")) {
        const rect = sec.getBoundingClientRect();
        if (rect.width > 200 && rect.height > 150 && rect.left > 150) {
          extLog("[SmartDM] Found regular WhatsApp section via section.x6egj2d (replacing section content only)");
          return sec;
        }
      }
    }
    const introPanel = document.querySelector("[data-asset-intro-image]");
    if (introPanel) {
      const container = introPanel.closest('div[class*="x1n2onr6"]');
      if (container && container.querySelector("h1, h2")) {
        extLog("[SmartDM] Found intro panel via data-asset");
        return container;
      }
    }
    const titleCandidates = document.querySelectorAll("h1, span");
    for (const el of titleCandidates) {
      const text = el.textContent ?? "";
      const isTarget = text.includes("WhatsApp") && (text.includes("Web") || text.includes("Windows") || text.includes("Download")) || text.includes("WhatsApp Business on Web");
      if (!isTarget)
        continue;
      let parent = el.parentElement;
      while (parent && parent.tagName !== "BODY") {
        const rect = parent.getBoundingClientRect();
        const hasVisual = parent.querySelector("svg, img, button");
        if (rect.height > 200 && rect.width > 200 && rect.left > 150 && hasVisual) {
          extLog("[SmartDM] Found container via title text:", text.substring(0, 40));
          return parent;
        }
        parent = parent.parentElement;
      }
    }
    const landingSection = document.querySelector("div._ak8q");
    if (landingSection && landingSection.offsetHeight > 200) {
      extLog("[SmartDM] Found landing section via _ak8q");
      return landingSection;
    }
    const encryptedText = Array.from(document.querySelectorAll("div, span")).find(
      (el) => el.textContent?.includes("end-to-end encrypted")
    );
    if (encryptedText) {
      let parent = encryptedText.parentElement;
      while (parent && parent.tagName !== "BODY") {
        if (parent.offsetHeight > 400 && parent.offsetWidth > 400) {
          const rect = parent.getBoundingClientRect();
          if (rect.left > 200) {
            extLog("[SmartDM] Found container via encrypted text");
            return parent;
          }
        }
        parent = parent.parentElement;
      }
    }
    const main = document.getElementById("main");
    const noChatOpen = main && !main.querySelector("[data-id]");
    if (noChatOpen && main) {
      const mainRect = main.getBoundingClientRect();
      if (mainRect.width < 200 || mainRect.height < 200)
        return null;
      const regularSection = main.querySelector('section[class*="x6egj2d"]');
      if (regularSection && regularSection.offsetHeight > 200) {
        extLog("[SmartDM] Found container via section.x6egj2d (regular WhatsApp Download for Windows)");
        return regularSection;
      }
      const outerWrapper = main.querySelector("div.x9f619.x1n2onr6.xupqr0c");
      if (outerWrapper && outerWrapper.offsetHeight > 200 && outerWrapper.querySelector('section[class*="x6egj2d"]')) {
        const rect = outerWrapper.getBoundingClientRect();
        if (rect.left > 200) {
          extLog("[SmartDM] Found container via x9f619.x1n2onr6 wrapper (regular WhatsApp)");
          return outerWrapper;
        }
      }
      let sameClassAsBusiness = main.querySelector(".xktia5q");
      if (!sameClassAsBusiness)
        sameClassAsBusiness = document.querySelector(".xktia5q");
      if (sameClassAsBusiness && sameClassAsBusiness.offsetHeight > 200) {
        const rect = sameClassAsBusiness.getBoundingClientRect();
        if (rect.left > 200) {
          extLog("[SmartDM] Found container via .xktia5q (Business)");
          return sameClassAsBusiness;
        }
      }
      const introClassInMain = main.querySelector('div[class*="x1n2onr6"]');
      if (introClassInMain && introClassInMain.offsetHeight > 200 && introClassInMain.querySelector('h1, h2, [role="button"], button')) {
        extLog("[SmartDM] Found container via x1n2onr6 in #main");
        return introClassInMain;
      }
      const assetInMain = main.querySelector("[data-asset-intro-image]");
      if (assetInMain) {
        const container = assetInMain.closest('div[class*="x1n2onr6"]');
        if (container && container.offsetHeight > 200) {
          extLog("[SmartDM] Found container via data-asset in #main");
          return container;
        }
      }
      const emptyStateMarkers = [
        (el) => (el.textContent ?? "").includes("Download") && (el.textContent ?? "").includes("WhatsApp"),
        (el) => (el.textContent ?? "").includes("Get extra features"),
        (el) => (el.textContent ?? "").includes("screen sharing"),
        (el) => (el.textContent ?? "").includes("voice and video calling"),
        (el) => /Send document|Add contact|Отправить документ|Добавить контакт/i.test(el.textContent ?? "")
      ];
      let anchor = null;
      for (const test of emptyStateMarkers) {
        anchor = Array.from(main.querySelectorAll("div, span, p, h1, h2")).find(test) ?? null;
        if (anchor)
          break;
      }
      if (anchor) {
        let node = anchor;
        let contentWrapper = null;
        while (node && node !== document.body) {
          if (node.parentElement === main) {
            contentWrapper = node;
            break;
          }
          node = node.parentElement;
        }
        if (contentWrapper && contentWrapper instanceof HTMLElement) {
          extLog("[SmartDM] Found container via empty-state text, direct child of #main (regular WhatsApp)");
          return contentWrapper;
        }
        let parent = anchor.parentElement;
        while (parent && parent !== main && parent.tagName !== "BODY") {
          const h = parent.offsetHeight;
          const w = parent.offsetWidth;
          if (h >= 250 && w >= 200) {
            extLog("[SmartDM] Found container via empty-state text in #main (regular WhatsApp)");
            return parent;
          }
          parent = parent.parentElement;
        }
      }
      for (let i = 0; i < main.children.length; i++) {
        const el = main.children[i];
        if (el.offsetHeight > 200 && el.offsetWidth > 200) {
          extLog("[SmartDM] Found container via #main first large child (regular WhatsApp)");
          return el;
        }
      }
      extLog("[SmartDM] Using #main as container (regular WhatsApp)");
      return main;
    }
    return null;
  }
  async function injectWelcomePanel() {
    if (document.getElementById("smartdm-welcome-panel")) {
      return;
    }
    const container = findMainContainer();
    if (!container) {
      return;
    }
    const [{ user, workspace, realtimeUsage }, { locale = "en" }] = await Promise.all([
      getUserData(),
      chrome.storage.local.get(["locale"])
    ]);
    const tr = (0, import_i18n.getTranslations)(locale);
    try {
      chrome.runtime.sendMessage({ type: "FETCH_USAGE" });
    } catch (e) {
    }
    const theme = getTheme();
    const wrapper = document.createElement("div");
    wrapper.id = "smartdm-welcome-wrapper";
    wrapper.style.cssText = `
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;
    min-height: 400px;
    background: ${theme.wrapperBg};
  `;
    if (user) {
      extLog("[SmartDM] Injecting authenticated panel for:", user.email || user.name);
      wrapper.innerHTML = createWelcomePanelHTML(user, workspace, realtimeUsage, tr);
      container.innerHTML = "";
      container.appendChild(wrapper);
      addButtonEffects();
      addClickHandlers();
    } else {
      extLog("[SmartDM] Injecting landing panel for unauthenticated user");
      wrapper.innerHTML = createLandingPanelHTML(tr);
      container.innerHTML = "";
      container.appendChild(wrapper);
      addLandingClickHandlers();
    }
    panelInjected = true;
    extLog("[SmartDM] Welcome panel injected successfully");
  }
  function checkAndInject() {
    if (document.getElementById("smartdm-welcome-panel"))
      return;
    const businessIndicators = [
      '[data-icon="wds-smb-ill-start-a-chat"]',
      "[data-asset-intro-image]",
      "div._ak8q"
    ];
    const hasBusiness = businessIndicators.some((sel) => document.querySelector(sel));
    const hasRegularSection = !!document.querySelector('section.x6egj2d, section[class*="x6egj2d"]');
    const mainPanel = document.getElementById("main");
    const hasConversation = mainPanel?.querySelector("[data-id]");
    const shouldInject = hasBusiness || hasRegularSection || mainPanel && !hasConversation || !mainPanel;
    if (shouldInject) {
      const container = findMainContainer();
      if (container) {
        injectWelcomePanel();
      }
    }
  }
  async function initWelcomePanel() {
    setTimeout(checkAndInject, 1e3);
    const observer = new MutationObserver(() => {
      setTimeout(checkAndInject, 100);
    });
    observer.observe(document.body, {
      childList: true,
      subtree: true
    });
    chrome.storage.onChanged.addListener((changes, area) => {
      if (area !== "local")
        return;
      const panel = document.getElementById("smartdm-welcome-panel");
      if (!panel)
        return;
      if (changes.realtimeUsage) {
        const ru = changes.realtimeUsage.newValue;
        if (!ru)
          return;
        const messagesEl = panel.querySelector('[data-stat="messages"]');
        if (messagesEl)
          messagesEl.textContent = String(ru.messagesSent || 0);
        const aiEl = panel.querySelector('[data-stat="ai"]');
        if (aiEl) {
          const aiLimit = ru.aiRepliesLimit || 10;
          const currentTheme = getTheme();
          aiEl.innerHTML = `${ru.aiReplies || 0}<span style="font-size: 16px; color: ${currentTheme.textMuted}; font-weight: 500;">/${aiLimit === -1 ? "\u221E" : aiLimit}</span>`;
        }
      }
      if (changes.workspace) {
        const newWorkspace = changes.workspace.newValue;
        if (!newWorkspace?.plan)
          return;
        const planNameEl = panel.querySelector('[data-stat="plan-name"]');
        if (planNameEl) {
          const newPlanName = newWorkspace.plan.name || "Free";
          planNameEl.textContent = `${newPlanName} Plan`;
          extLog("[SmartDM] \u2705 Plan name updated in UI:", newPlanName);
        } else {
          panelInjected = false;
          document.getElementById("smartdm-welcome-wrapper")?.remove();
        }
      }
    });
    extLog("[SmartDM] Welcome panel injector initialized");
  }

