  function wasTourCompleted() {
    return new Promise((resolve) => {
      try {
        chrome.runtime.sendMessage({ type: "GET_TOUR_COMPLETED" }, (response) => {
          if (chrome.runtime.lastError) {
            resolve(false);
            return;
          }
          resolve(!!response?.completed);
        });
      } catch {
        resolve(false);
      }
    });
  }
  function markTourCompleted() {
    return new Promise((resolve, reject) => {
      try {
        chrome.runtime.sendMessage({ type: "SET_TOUR_COMPLETED" }, (response) => {
          if (chrome.runtime.lastError) {
            reject(chrome.runtime.lastError);
            return;
          }
          if (response?.success !== false)
            resolve();
          else
            reject(new Error("SET_TOUR_COMPLETED failed"));
        });
      } catch (e) {
        reject(e);
      }
    });
  }
  function getTooltipPosition(step, target, tooltipHeight = 220) {
    const padding = 16;
    const maxWidth = 340;
    if (!target || step.placement === "center") {
      return {
        top: Math.max(padding, window.innerHeight / 2 - 120),
        left: Math.max(padding, (window.innerWidth - maxWidth) / 2),
        maxWidth
      };
    }
    const rect = target.getBoundingClientRect();
    const gap = 12;
    switch (step.placement) {
      case "top":
        return {
          top: rect.top - tooltipHeight - gap,
          left: rect.left + rect.width / 2 - maxWidth / 2,
          maxWidth
        };
      case "bottom":
        return {
          top: rect.bottom + gap,
          left: rect.left + rect.width / 2 - maxWidth / 2,
          maxWidth
        };
      case "left":
        return {
          top: rect.top + rect.height / 2 - 80,
          left: rect.left - maxWidth - gap,
          maxWidth
        };
      case "right":
        return {
          top: rect.top + rect.height / 2 - 80,
          left: rect.right + gap,
          maxWidth
        };
      default:
        return {
          top: rect.bottom + gap,
          left: rect.left,
          maxWidth
        };
    }
  }
  function clampTooltip(top, left, maxWidth, tooltipHeight) {
    const padding = 12;
    return {
      top: Math.max(padding, Math.min(window.innerHeight - tooltipHeight - padding, top)),
      left: Math.max(padding, Math.min(window.innerWidth - maxWidth - padding, left))
    };
  }
  var DIM_STYLE = `background: rgba(0,0,0,${DIM_OPACITY}); pointer-events: auto;`;
  function createOverlay() {
    const existing = document.getElementById(OVERLAY_ID);
    if (existing)
      return existing;
    const overlay = document.createElement("div");
    overlay.id = OVERLAY_ID;
    overlay.style.cssText = `
    position: fixed;
    inset: 0;
    z-index: 2147483646;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    pointer-events: none;
  `;
    document.body.appendChild(overlay);
    return overlay;
  }
  function updateOverlayForStep(overlay, target) {
    overlay.innerHTML = "";
    if (!target) {
      const full = document.createElement("div");
      full.style.cssText = `position: fixed; inset: 0; ${DIM_STYLE}`;
      overlay.appendChild(full);
      return;
    }
    const rect = target.getBoundingClientRect();
    const p = SPOTLIGHT_PADDING;
    const top = Math.max(0, rect.top - p);
    const left = Math.max(0, rect.left - p);
    const right = Math.min(window.innerWidth, rect.right + p);
    const bottom = Math.min(window.innerHeight, rect.bottom + p);
    const w = window.innerWidth;
    const h = window.innerHeight;
    const panels = [
      { top: "0", left: "0", width: `${w}px`, height: `${top}px` },
      { top: `${top}px`, left: "0", width: `${left}px`, height: `${bottom - top}px` },
      { top: `${top}px`, left: `${right}px`, width: `${w - right}px`, height: `${bottom - top}px` },
      { top: `${bottom}px`, left: "0", width: `${w}px`, height: `${h - bottom}px` }
    ];
    panels.forEach((pos) => {
      const div = document.createElement("div");
      div.style.cssText = `position: fixed; top: ${pos.top}; left: ${pos.left}; width: ${pos.width}; height: ${pos.height}; ${DIM_STYLE}`;
      overlay.appendChild(div);
    });
    const hole = document.createElement("div");
    hole.className = "sdm-spotlight-hole";
    hole.style.cssText = `
    position: fixed;
    top: ${top}px;
    left: ${left}px;
    width: ${right - left}px;
    height: ${bottom - top}px;
    border-radius: ${SPOTLIGHT_BORDER_RADIUS}px;
    background: transparent;
    box-shadow: 0 0 0 9999px rgba(0,0,0,${DIM_OPACITY});
    pointer-events: none;
  `;
    overlay.appendChild(hole);
  }
