  function getChatMessagesFromDOM(limit = 10) {
    const messages = [];
    try {
      extLog("[SmartDM] Extracting messages from DOM...");
      const chatContainer = document.querySelector('#main [role="application"]') || document.querySelector("#main .copyable-area") || document.querySelector('[data-testid="conversation-panel-messages"]');
      if (!chatContainer) {
        extLog("[SmartDM] Chat container not found");
        return messages;
      }
      let messageRows = chatContainer.querySelectorAll("[data-id]");
      extLog("[SmartDM] Found", messageRows.length, "elements with data-id");
      if (messageRows.length === 0) {
        messageRows = chatContainer.querySelectorAll(".message-in, .message-out");
        extLog("[SmartDM] Found", messageRows.length, "message-in/out elements");
      }
      if (messageRows.length === 0) {
        messageRows = chatContainer.querySelectorAll('[role="row"]');
        extLog("[SmartDM] Found", messageRows.length, "role=row elements");
      }
      const chatMessages = [];
      let index = 0;
      messageRows.forEach((row) => {
        let textContent = "";
        const selectableText = row.querySelector("span.selectable-text");
        if (selectableText) {
          const innerSpan = selectableText.querySelector("span");
          textContent = innerSpan?.textContent?.trim() || selectableText.textContent?.trim() || "";
        }
        if (!textContent) {
          const copyableText = row.querySelector(".copyable-text");
          if (copyableText) {
            textContent = copyableText.textContent?.trim() || "";
          }
        }
        if (!textContent) {
          const prePlainTextEl = row.querySelector("[data-pre-plain-text]");
          if (prePlainTextEl) {
            const fullText = prePlainTextEl.textContent?.trim() || "";
            textContent = fullText;
          }
        }
        if (!textContent || textContent.length < 1)
          return;
        let isOutgoing = false;
        const dataId = row.getAttribute("data-id");
        if (dataId) {
          isOutgoing = dataId.startsWith("true_");
        } else {
          isOutgoing = row.classList.contains("message-out") || row.closest(".message-out") !== null || row.querySelector('[data-icon="msg-dblcheck"]') !== null || row.querySelector('[data-icon="msg-check"]') !== null;
        }
        chatMessages.push({
          element: row,
          isOutgoing,
          text: textContent,
          index: index++
        });
      });
      extLog("[SmartDM] Extracted", chatMessages.length, "valid messages");
      const lastMessages = chatMessages.slice(-limit);
      for (const msg of lastMessages) {
        messages.push({
          role: msg.isOutgoing ? "me" : "contact",
          text: msg.text
        });
      }
      extLog("[SmartDM] Returning", messages.length, "messages for summary");
    } catch (error) {
      console.error("[SmartDM] Error extracting messages from DOM:", error);
    }
    return messages;
  }
