  function detectNameFromHeader() {
    const preferredSelectors = [
      '#main header [data-testid="conversation-info-header-chat-title"]',
      '#main header [data-testid="conversation-info-header-chat-title"] span',
      "#main header span[title]",
      '#main header span[dir="auto"]',
      'header[data-testid="conversation-header"] span',
      '#pane-side [aria-selected="true"] span[dir="auto"]'
    ];
    for (const sel of preferredSelectors) {
      const els = document.querySelectorAll(sel);
      for (const el of els) {
        const value = (el.getAttribute("title") || el.textContent || "").trim();
        if (!value)
          continue;
        if (isHeaderPlaceholderText(value))
          continue;
        return value;
      }
    }
    const allHeaderSpans = document.querySelectorAll("#main header span, header[data-testid] span");
    for (const el of allHeaderSpans) {
      const value = (el.getAttribute("title") || el.textContent || "").trim();
      if (!value)
        continue;
      if (isHeaderPlaceholderText(value))
        continue;
      return value;
    }
    return "";
  }
  var cachedWAContactId = "";
