  async function addCurrentContactToCRM(buttonEl) {
    if (!requireLogin(buttonEl))
      return false;
    const btn = buttonEl;
    const originalText = btn?.textContent || "+ Add";
    if (btn) {
      btn.disabled = true;
      btn.textContent = "Adding...";
    }
    try {
      const { phone, name } = await resolveCurrentContactForCrmCreate();
      if (!phone) {
        showToast("Could not detect contact phone. Open the chat and try again.", "warning");
        if (btn) {
          btn.disabled = false;
          btn.textContent = originalText;
        }
        return false;
      }
      currentContactPhone = phone;
      currentContactName = name || phone;
      const response = await new Promise((resolve) => {
        chrome.runtime.sendMessage(
          { type: "CREATE_CONTACT", payload: { phone, name: currentContactName } },
          (r) => {
            if (chrome.runtime.lastError) {
              resolve({ success: false, error: chrome.runtime.lastError.message });
              return;
            }
            resolve(r || { success: false, error: "No response" });
          }
        );
      });
      if (!response?.success) {
        showToast(response?.error || "Failed to add contact to CRM", "error");
        if (btn) {
          btn.disabled = false;
          btn.textContent = originalText;
        }
        return false;
      }
      if (response.existing) {
        showToast("Contact is already in CRM", "warning");
      } else {
        showToast("Contact added to CRM successfully", "success");
      }
      window.dispatchEvent(new CustomEvent("smartdm-contact-added-to-crm", { detail: { phone, name: currentContactName } }));
      await fetchCRMContactData(phone, currentContactName);
      return true;
    } catch (error) {
      console.error("[SmartDM] Error adding contact to CRM:", error);
      showToast("Error adding contact to CRM. Please try again.", "error");
      if (btn) {
        btn.disabled = false;
        btn.textContent = originalText;
      }
      return false;
    }
  }
